// ============================================================
// FILTRO — extrai mensagem e detecta tipo de mídia
// ============================================================
const body = $input.first().json;
const payload = body.body ?? body;

if (payload.event !== 'messages.upsert') return [];

const data = payload.data;
if (!data?.key) return [];
if (data.key.fromMe === true) return [];
if (data.key.remoteJid.includes('@g.us')) return [];
if (data.key.remoteJid.includes('@broadcast')) return [];

let messageText = '';
let mediaType = 'text';
const msg = data.message ?? {};

if (msg.conversation) {
  messageText = msg.conversation;
} else if (msg.extendedTextMessage?.text) {
  messageText = msg.extendedTextMessage.text;
} else if (msg.imageMessage) {
  mediaType = 'image';
  messageText = msg.imageMessage.caption
    ? '[Foto com legenda: ' + msg.imageMessage.caption + ']'
    : '[Cliente enviou uma foto do ambiente]';
} else if (msg.videoMessage) {
  mediaType = 'video';
  messageText = msg.videoMessage.caption
    ? '[Video com legenda: ' + msg.videoMessage.caption + ']'
    : '[Cliente enviou um video]';
} else if (msg.audioMessage) {
  mediaType = 'audio';
  const secs = msg.audioMessage.seconds || 0;
  messageText = '[Audio de ' + secs + ' segundos]';
} else if (msg.documentMessage) {
  mediaType = 'document';
  const fname = msg.documentMessage.fileName || 'documento';
  const mime = msg.documentMessage.mimetype || '';
  if (mime.includes('pdf')) {
    messageText = '[PDF recebido: ' + fname + ']';
  } else {
    messageText = '[Documento recebido: ' + fname + ']';
  }
} else if (msg.stickerMessage || msg.reactionMessage) {
  return [];
} else if (msg.contactMessage || msg.contactsArrayMessage) {
  mediaType = 'contact';
  messageText = '[Cliente compartilhou um contato]';
} else if (msg.locationMessage || msg.liveLocationMessage) {
  mediaType = 'location';
  messageText = '[Cliente enviou uma localizacao]';
} else {
  return [];
}

if (!messageText.trim()) return [];

const phone = data.key.remoteJid.replace('@s.whatsapp.net', '');

return [{
  json: {
    phone,
    remoteJid: data.key.remoteJid,
    pushName: data.pushName ?? 'Cliente',
    messageText: messageText.trim(),
    mediaType
  }
}];

// ============================================================
// DEBOUNCE — acumula mensagens do mesmo remetente
// Espera 4s antes de processar para juntar mensagens seguidas
// ============================================================
const { phone, messageText, pushName, remoteJid, mediaType } = $input.first().json;

const db = $getWorkflowStaticData('global');
if (!db.msgBuffer) db.msgBuffer = {};

const batchId = Date.now().toString() + '_' + Math.random().toString(36).substr(2, 6);

if (!db.msgBuffer[phone]) {
  db.msgBuffer[phone] = { messages: [], pushName, remoteJid };
}

db.msgBuffer[phone].messages.push({ text: messageText, mediaType });
db.msgBuffer[phone].batchId = batchId;
db.msgBuffer[phone].pushName = pushName;
db.msgBuffer[phone].remoteJid = remoteJid;

return [{ json: { phone, batchId } }];

// ============================================================
// DEBOUNCE CHECK — só processa o lote mais recente
// Se o cliente mandou mais msgs nos últimos 4s, aborta
// ============================================================
const { phone, batchId } = $input.first().json;

const db = $getWorkflowStaticData('global');
if (!db.msgBuffer || !db.msgBuffer[phone]) return [];

// Lote mais novo chegou? Aborta esta execução silenciosamente
if (db.msgBuffer[phone].batchId !== batchId) return [];

// Somos o mais recente — coletar todas as mensagens acumuladas
const buf = db.msgBuffer[phone];
const texts = buf.messages.map(m => m.text);
const combined = texts.join('\n');
const hasAudio = buf.messages.some(m => m.mediaType === 'audio');
const hasDoc = buf.messages.some(m => m.mediaType === 'document');
const hasImage = buf.messages.some(m => m.mediaType === 'image' || m.mediaType === 'video');
const hasLocation = buf.messages.some(m => m.mediaType === 'location');
const hasContact = buf.messages.some(m => m.mediaType === 'contact');
const count = buf.messages.length;

// Limpar buffer deste telefone
delete db.msgBuffer[phone];

return [{
  json: {
    phone,
    remoteJid: buf.remoteJid,
    pushName: buf.pushName,
    messageText: combined,
    hasAudio,
    hasDocument: hasDoc,
    hasImage,
    hasLocation,
    hasContact,
    messageCount: count
  }
}];

// ============================================================
// MEMÓRIA — histórico + contexto temporal + reset humano
// ============================================================

// ── Controles: IA ligada? Número bloqueado? ──
const cfg = $input.first().json;
if (!cfg.ia_enabled) return []; // IA desligada no painel

const configData = $('🔄 Verificar Lote').first().json;
const { phone, pushName, messageText, remoteJid, hasAudio, hasDocument, hasImage, hasLocation, hasContact, messageCount } = configData;

const blocked = (cfg.blocked_phones || '').split(',').map(p => p.trim()).filter(Boolean);
if (blocked.includes(phone)) return []; // Número na lista de bloqueio

const db = $getWorkflowStaticData('global');
if (!db.conversations) db.conversations = {};

const TWO_HOURS = 2 * 60 * 60 * 1000;
let conv = db.conversations[phone];

if (!conv) {
  conv = {
    history: [],
    stage: 'new',
    name: pushName,
    phone,
    createdAt: new Date().toISOString(),
    lastActivity: new Date().toISOString()
  };
}

// Reset automático: se estava em atendimento humano há mais de 2h, volta para IA
if (conv.stage === 'human') {
  const last = new Date(conv.lastActivity).getTime();
  if (Date.now() - last > TWO_HOURS) {
    conv.stage = 'active';
  }
}

conv.name = pushName;
conv.lastActivity = new Date().toISOString();
conv.history.push({ role: 'user', content: messageText });

// Manter últimas 40 mensagens para contexto
if (conv.history.length > 40) {
  conv.history = conv.history.slice(-40);
}

db.conversations[phone] = conv;

// Hora de São Luís (UTC-3)
const now = new Date();
const brTime = new Date(now.getTime() - 3 * 3600000);
const h = brTime.getUTCHours();
const m = brTime.getUTCMinutes();
const dias = ['domingo','segunda','terca','quarta','quinta','sexta','sabado'];
const dia = dias[brTime.getUTCDay()];

let periodo = 'madrugada';
if (h >= 6 && h < 12) periodo = 'manha';
else if (h >= 12 && h < 18) periodo = 'tarde';
else if (h >= 18 && h < 23) periodo = 'noite';

const bizDay = brTime.getUTCDay() >= 1 && brTime.getUTCDay() <= 5;
const bizHour = h >= 8 && h < 18;
const satMorning = brTime.getUTCDay() === 6 && h >= 8 && h < 13;
const horarioComercial = (bizDay && bizHour) || satMorning;

return [{
  json: {
    phone, remoteJid, pushName, messageText,
    history: conv.history,
    stage: conv.stage,
    hasAudio, hasDocument, hasImage, hasLocation, hasContact, messageCount,
    hora: h.toString().padStart(2, '0') + ':' + m.toString().padStart(2, '0'),
    periodo, dia, horarioComercial,
    totalExchanges: conv.history.length
  }
}];

// ============================================================
// PROCESSAR RESPOSTA — salvar no histórico + detectar handoff
// ============================================================
const claudeResponse = $input.first().json;
const prevData = $('💾 Carregar Histórico').first().json;

let aiText = '';
if (claudeResponse.content && claudeResponse.content.length > 0) {
  aiText = claudeResponse.content[0].text ?? '';
} else if (claudeResponse.error) {
  aiText = 'Desculpe, tive um problema técnico. Em instantes nossa equipe entra em contato com você.';
}

const isHandoff = aiText.includes('[HANDOFF]');
const cleanText = aiText.replace('[HANDOFF]', '').trim();

const phone = prevData.phone;
const db = $getWorkflowStaticData('global');
if (!db.conversations) db.conversations = {};
if (!db.conversations[phone]) db.conversations[phone] = { history: [], stage: 'new' };

if (isHandoff) {
  db.conversations[phone].stage = 'human';
}

db.conversations[phone].history.push({
  role: 'assistant',
  content: cleanText
});

// Delay proporcional ao tamanho da resposta (parece humano)
const typingDelayMs = Math.min(Math.max(cleanText.length * 25, 1500), 5000);

return [{
  json: {
    phone,
    remoteJid: prevData.remoteJid,
    pushName: prevData.pushName,
    userText: prevData.messageText,
    aiText: cleanText,
    isHandoff,
    typingDelayMs
  }
}];

